    def register_processor(self, message_type: str, processor: MessageProcessor):
        """
        Registers a message processor for a specific message type.
        :param message_type: The string identifier for the message type (e.g., 'echo', 'send_email').
        :param processor: An instance of a class inheriting from MessageProcessor.
        """
